# Create a policy that requires Environment tag with specific allowed values
az policy definition create \
  --name require-environment-tag-values \
  --mode Indexed \
  --display-name 'Require Environment tag with approved values' \
  --rules '{
    "if": {
      "not": {
        "field": "tags[Environment]",
        "in": ["prod", "staging", "dev", "test", "sandbox"]
      }
    },
    "then": { "effect": "deny" }
  }'

# Assign at management group scope
az policy assignment create \
  --name require-environment-tag-values \
  --policy require-environment-tag-values \
  --management-group mg-corp

# Alternative: use a built-in policy with parameter
BUILTIN=$(az policy definition list \
  --query "[?displayName=='Require a tag and its value on resources'].id" -o tsv | head -1)

# Assign for CostCenter with allowed values
az policy assignment create \
  --name require-costcenter-tag-values \
  --policy $BUILTIN \
  --management-group mg-corp \
  --params '{
    "tagName": {"value": "CostCenter"},
    "tagValue": {"value": "eng-platform"}
  }'
# Note: built-in 'Require a tag and its value' only supports one allowed value
# For multiple allowed values, use a custom policy with 'in' operator

// Policy initiative definition for organization-wide tagging
{
  "properties": {
    "displayName": "Org-wide Tagging Initiative",
    "policyType": "Custom",
    "parameters": {
      "requiredTagNames": {
        "type": "Array",
        "defaultValue": ["CostCenter", "Environment", "Owner", "Application"],
        "metadata": { "displayName": "Required tag names" }
      }
    },
    "policyDefinitions": [
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99",
        "definitionVersion": "1.*.*",
        "policyDefinitionReferenceId": "requireCostCenterTag",
        "parameters": { "tagName": { "value": "CostCenter" } }
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99",
        "policyDefinitionReferenceId": "requireEnvironmentTag",
        "parameters": { "tagName": { "value": "Environment" } }
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/871b6d14-10aa-478d-b590-94f262ecfa99",
        "policyDefinitionReferenceId": "requireOwnerTag",
        "parameters": { "tagName": { "value": "Owner" } }
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/cd3aa116-8754-49c9-a813-ad46512ece54",
        "policyDefinitionReferenceId": "inheritCostCenterFromRG",
        "parameters": { "tagName": { "value": "CostCenter" } }
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/cd3aa116-8754-49c9-a813-ad46512ece54",
        "policyDefinitionReferenceId": "inheritEnvironmentFromRG",
        "parameters": { "tagName": { "value": "Environment" } }
      }
    ]
  }
}
